import { promisify } from 'node:util';
import { unzip, unzipSync } from 'node:zlib';
const unzipPromise = promisify(unzip);
export const decompress = async (data) => JSON.parse((await unzipPromise(data)).toString());
// eslint-disable-next-line @typescript-eslint/no-unnecessary-type-parameters
export const decompressSync = (data) => JSON.parse(unzipSync(data).toString());
